import{_ as i,o as e,c as a,ai as t}from"./chunks/framework.BZ-K7CQ_.js";const c=JSON.parse('{"title":"Backups on a self-hosted install","description":"","frontmatter":{},"headers":[],"relativePath":"backups.md","filePath":"backups.md"}'),n={name:"backups.md"};function o(h,s,l,r,d,p){return e(),a("div",null,[...s[0]||(s[0]=[t(`<h1 id="backups-on-a-self-hosted-install" tabindex="-1">Backups on a self-hosted install <a class="header-anchor" href="#backups-on-a-self-hosted-install" aria-label="Permalink to “Backups on a self-hosted install”">​</a></h1><p>Self-hosted Arcsecond writes a compressed Postgres dump in two situations:</p><ul><li><strong>On every backend container boot</strong>, before migrations run — so you always have a pre-migration snapshot to fall back to if an upgrade goes wrong.</li><li><strong>Every hour</strong> afterwards, via a Celery periodic task.</li></ul><p>A daily cleanup task then prunes dumps older than 14 days. This page covers where backups live, how to list / inspect / restore them with the <code>arcsecond backups</code> command, and what else you should copy off-host for full disaster recovery.</p><h2 id="where-backups-are-stored" tabindex="-1">Where backups are stored <a class="header-anchor" href="#where-backups-are-stored" aria-label="Permalink to “Where backups are stored”">​</a></h2><p>Backups are written by the backend to the host directory you picked as <code>SHARED_DATA_PATH</code> during <code>arcsecond hosting setup</code>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>$SHARED_DATA_PATH/db_backups/</span></span>
<span class="line"><span>├── backup-20260514-031502.sql.gz       # auto, on boot or hourly</span></span>
<span class="line"><span>├── backup-20260515-021100.sql.gz</span></span>
<span class="line"><span>└── pre-restore-20260515-104230.sql.gz  # auto, before any restore</span></span></code></pre></div><ul><li><code>backup-YYYYMMDD-HHMMSS.sql.gz</code> — gzipped plain-SQL dump of the entire DB (<code>arcsecond_docker</code> database, owned by user <code>arcsecond_docker</code>). The timestamp is in <strong>UTC</strong>.</li><li><code>pre-restore-YYYYMMDD-HHMMSS.sql.gz</code> — safety snapshot taken automatically just before any <code>arcsecond backups restore</code>.</li></ul><p>If you want retention longer than 14 days, ship dumps off-host (see below).</p><h2 id="listing-and-inspecting-backups" tabindex="-1">Listing and inspecting backups <a class="header-anchor" href="#listing-and-inspecting-backups" aria-label="Permalink to “Listing and inspecting backups”">​</a></h2><p>All commands must be run <strong>from the install directory</strong> (the one containing <code>docker-compose.yml</code> and <code>.env</code>).</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arcsecond</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backups</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p>Prints the newest-first table of backups with a compatibility badge against the currently running backend image. The badge reflects the diff between the <code>django_migrations</code> table recorded in the dump and the migrations shipped by the image:</p><ul><li><strong>compatible</strong> — same migration set; restore is safe.</li><li><strong>older snapshot</strong> — the running code has migrations the backup doesn&#39;t. This is the normal state for the boot-time backup taken just before an upgrade: the backup is fine, it&#39;s simply older than the live DB. Restoring it rolls back to the pre-upgrade state. The CLI annotates this with <code>(+N migration(s) applied since)</code> so you know how far behind it is.</li><li><strong>incompatible</strong> — the dump contains migrations the running code does not know about (most often because migrations were renamed, removed, or squashed during development). Restoring would also require rolling the code back to a commit that knew those migrations. The CLI annotates with <code>(-N not in code, +M applied since)</code> to make the shape of the diff obvious.</li><li><strong>unknown</strong> — backend container is not running, so no diff is possible.</li><li><strong>broken</strong> — the file isn&#39;t a valid gzip (truncated, wrong magic bytes, or empty). Not restorable; delete it.</li></ul><p>After the table, <code>list</code> prints a one-paragraph footer about the most recent backup when it isn&#39;t <code>compatible</code> — typically explaining the &quot;older snapshot&quot; case so a fresh post-upgrade <code>list</code> doesn&#39;t look alarming.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arcsecond</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backups</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> inspect</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backup-20260515-021100.sql.gz</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # or just the index</span></span></code></pre></div><p>Shows file size, mtime, migration counts, and the exact list of migrations that differ between the dump and the running image.</p><h2 id="restoring-a-backup" tabindex="-1">Restoring a backup <a class="header-anchor" href="#restoring-a-backup" aria-label="Permalink to “Restoring a backup”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arcsecond</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backups</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restore</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # interactive picker</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arcsecond</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backups</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restore</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # by list index</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arcsecond</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backups</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restore</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backup-20260515-021100.sql.gz</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # by filename</span></span></code></pre></div><p><code>restore</code> will, in order:</p><ol><li>Verify <code>POSTGRES_PASSWORD</code> is set in <code>.env</code>.</li><li>Refuse to proceed if the backup is <code>incompatible</code> (override with <code>--force</code>, knowing you may be restoring a dump newer than the code).</li><li>Take a <code>pre-restore-…sql.gz</code> safety snapshot (skip with <code>--no-safety-backup</code> — not recommended).</li><li>Stop <code>arcsecond-api</code>, <code>arcsecond-worker</code>, <code>arcsecond-beat</code>, <code>arcsecond-web</code> (the DB container stays up so the dump can be piped in).</li><li>Drop and recreate the <code>arcsecond_docker</code> database.</li><li><code>gunzip -c &lt;backup&gt; | docker exec -i arcsecond-db psql …</code></li><li>Restart the stopped services.</li></ol><p>Use <code>--dry-run</code> to print every command without touching anything — useful for auditing what a restore would do, especially on a production host.</p><h2 id="what-else-to-back-up-off-host" tabindex="-1">What else to back up off-host <a class="header-anchor" href="#what-else-to-back-up-off-host" aria-label="Permalink to “What else to back up off-host”">​</a></h2><p>The auto-dump only covers the Postgres database. For a full disaster recovery, copy the following to off-host storage (S3, another machine, an external drive — whatever your operational practice is):</p><table tabindex="0"><thead><tr><th>Path</th><th>Why</th></tr></thead><tbody><tr><td><code>$SHARED_DATA_PATH/db_backups/</code></td><td>The DB dumps themselves.</td></tr><tr><td><code>$SHARED_DATA_PATH/</code></td><td>All uploaded data files and generated media — Postgres does <strong>not</strong> store these.</td></tr><tr><td><code>.env</code></td><td>DB password, Django <code>SECRET_KEY</code>, <code>AUTH_JWT_SIGNING_KEY</code>, <code>AGENT_JWT_SIGNING_KEY</code>, <code>FIELD_ENCRYPTION_KEY</code>. Without this, a restored DB is unusable: JWT-signed sessions break and field-level encrypted columns become unreadable. Keep it <code>chmod 600</code> and treat it like a private key.</td></tr><tr><td><code>docker-compose.yml</code></td><td>Only if you have customised it — otherwise <code>arcsecond hosting setup</code> rewrites it from the packaged template.</td></tr></tbody></table><p>Putting <code>.env</code> and the DB backups in the <strong>same</strong> off-host bucket means an attacker who breaches that bucket has both the data and the keys. Store them separately if you can.</p><h2 id="a-minimal-off-host-backup-recipe" tabindex="-1">A minimal off-host backup recipe <a class="header-anchor" href="#a-minimal-off-host-backup-recipe" aria-label="Permalink to “A minimal off-host backup recipe”">​</a></h2><p>A simple cron job that ships yesterday&#39;s auto-dump plus the secrets:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#!/usr/bin/env bash</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -euo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pipefail</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">INSTALL_DIR</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/srv/arcsecond</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                       # adjust</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">DEST</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">s3://your-bucket/arcsecond-backups/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hostname</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SHARED_DATA_PATH</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;^SHARED_DATA_PATH=&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$INSTALL_DIR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.env&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cut</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f2-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Latest auto-dump</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">latest</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -1t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$SHARED_DATA_PATH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/db_backups&quot;/backup-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.sql.gz</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aws</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> s3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$latest</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$DEST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/db/&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Secrets — keep in a separately-permissioned prefix</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aws</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> s3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$INSTALL_DIR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.env&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$DEST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/secrets/.env&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Uploaded data (incremental — rclone/restic are usually a better fit here)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aws</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> s3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$SHARED_DATA_PATH</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$DEST</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/shared-data/&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --exclude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;db_backups/*&quot;</span></span></code></pre></div><p>Restoring on a fresh host: install Arcsecond as usual, replace the generated <code>.env</code> with the backed-up one, drop the dump into <code>$SHARED_DATA_PATH/db_backups/</code>, then run <code>arcsecond backups restore</code>.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Troubleshooting”">​</a></h2><ul><li><strong><code>No backups directory found</code></strong> — you are not in the install directory, or the backend has never booted on this host. Run from the directory that has <code>docker-compose.yml</code> and <code>.env</code>, and start the stack at least once.</li><li><strong><code>POSTGRES_PASSWORD missing from .env</code></strong> — the restore command needs the live password to talk to Postgres. If you rotated it manually, make sure the <code>.env</code> value matches what the role actually has (see <a href="./rotate-postgres-password">rotating the Postgres password</a>).</li><li><strong><code>backend not running — skip migration diff</code></strong> during <code>list</code> / <code>inspect</code> — expected when the stack is down. Start the backend if you want the badge.</li><li><strong><code>Refusing to restore an incompatible backup</code></strong> — the dump contains migrations newer than the running image. Upgrade your image first; do not reach for <code>--force</code> unless you understand exactly what you are restoring.</li></ul>`,32)])])}const g=i(n,[["render",o]]);export{c as __pageData,g as default};
